	continue
}

// Found a candidate: clear any "idle" substate set on the previous
// no-candidate iteration (ddx-dc157075 AC #5).
if wasIdle && runtime.Log != nil {
	_, _ = fmt.Fprint(runtime.Log, workLog.FormatNextReadyTransition(candidate.ID, candidate.Title))
}
wasIdle = false
resetPreClaimIdleStreak()
emitProgress(runtime.ProgressCh, ProgressEvent{
	EventID:   "evt-" + randomProgressID(),
	WorkerID:  runtime.WorkerID,
	ProjectID: runtime.ProjectRoot,
	BeadID:    candidate.ID,
	Phase:     "loop.active",
	Heartbeat: true,
	TS:        now().UTC(),
})

if allowed, reason := complexityGuard.Allow(ctx, candidate.ID); !allowed {
	if runtime.Log != nil && reason != "" {
		_, _ = fmt.Fprintf(runtime.Log, "complexity gate: %s (skipping %s)\n", reason, candidate.ID)
	}
	continue
}
freshCandidate, staleSkip, refreshErr := w.refreshCandidateBeforeClaim(ctx, candidate)
if refreshErr != nil {
	return result, refreshErr
}
if staleSkip != nil {
	transientCandidateSkips[candidate.ID] = staleCandidateSkipReason
	if runtime.Log != nil {
		_, _ = fmt.Fprintf(runtime.Log, "picker skip stale candidate %s before claim: %s\n", candidate.ID, staleSkip.Detail)
	}
	emitStaleCandidateSkip(emit, candidate.ID, staleSkip, freshCandidate, "pre_claim")
	recordClaimAttempt(false, candidate.ID)
	if stopAfterNonAttemptSkip() {
		applyStop(work.StopInput{Once: true})
		return result, nil
	}
	continue
}
candidate = *freshCandidate
// Consecutive-wedge guard (ddx-9714eaac): if this bead wedged
// (route_resolution_timeout / progress_watchdog) on its immediately
// preceding claim(s) up to the threshold, stop re-claiming it. A
// route-independent wedge carries no failed-route entry, so without this
// guard a freshly released wedged bead is re-claimed and re-wedged
// indefinitely while ready work starves (parent ddx-8f2e0ebf criterion E).
// The bead is parked to proposed for operator attention; `continue` moves
// the loop on to the next ready bead so the queue keeps draining.
if marker := readWedgeMarker(candidate.Extra); consecutiveWedgeGuardTrips(marker, runtime.effectiveConsecutiveWedgeThreshold()) {
	threshold := runtime.effectiveConsecutiveWedgeThreshold()
	if parkErr := flagConsecutiveWedgeForOperator(w.Store, candidate.ID, assignee, marker, threshold, now().UTC()); parkErr != nil && runtime.Log != nil {
		_, _ = fmt.Fprintf(runtime.Log, "consecutive-wedge guard: failed to park %s for operator attention: %v\n", candidate.ID, parkErr)
	}
	emit("loop.consecutive_wedge_guard", map[string]any{
		"bead_id":     candidate.ID,
		"count":       marker.Count,
		"threshold":   threshold,
		"last_reason": marker.LastReason,
	})
	if runtime.Log != nil {
		_, _ = fmt.Fprintf(runtime.Log, "consecutive-wedge guard: %s wedged %d consecutive claims (>= %d); flagged for operator attention, continuing to next ready bead\n", candidate.ID, marker.Count, threshold)
	}
	recordClaimAttempt(false, candidate.ID)
	continue
}
// Claim atomically before model-backed intake and lint to prevent
// concurrent workers from issuing duplicate model calls or appending
// duplicate lint events for the same bead. Terminal non-actionable
// outcomes unclaim and park the bead rather than proceeding to execution.
var claimErr error
if claimer, ok := w.Store.(claimWithOptionsStore); ok {
	claimErr = claimer.ClaimWithOptions(candidate.ID, assignee, runtime.SessionID, "")
} else {
	claimErr = w.Store.Claim(candidate.ID, assignee)
}
if claimErr != nil {
	// Another worker won the race for this bead. Emit a structured
	// claim_race event so concurrent-worker losses are observable
	// (ddx-9d55601f AC #4). The bead remains in `attempted` for this
	// run; on the next iteration it will be filtered out of
	// ReadyExecution naturally because the winner now holds the fresh
	// claim lease sidecar, so the loser keeps moving down priority
	// order.
	emit("picker.claim_race", map[string]any{
		"bead_id":    candidate.ID,
		"priority":   candidate.Priority,
		"queue_rank": queueRankValue(candidate.Extra["queue-rank"]),
		"reason":     claimErr.Error(),
	})
	recordClaimAttempt(false, candidate.ID)
	continue
}
recordClaimAttempt(true, candidate.ID)

overrideRetryAfter := ""
overrideMeta := forcedCooldownMetadata{}
if runtime.IgnoreCooldown {
	if reporter, ok := w.Store.(cooldownOverrideReporter); ok {
		if retryAfter, overridden := reporter.CooldownOverrideInfo(candidate.ID); overridden {
			overrideRetryAfter = retryAfter
			overrideMeta = forcedCooldownSnapshot(candidate, retryAfter, true)
			appendForceClaimEvent(w.Store, candidate.ID, assignee, executeLoopEventSource(runtime), runtime.CooldownOverrideReason, retryAfter, now().UTC())
		}
	}
}

emit("bead.claimed", map[string]any{
	"bead_id":  candidate.ID,
	"title":    candidate.Title,
	"assignee": assignee,
})

if runtime.Log != nil {
	workLog = workLog.WithCurrentBeadID(candidate.ID)
	_, _ = fmt.Fprint(runtime.Log, workLog.FormatHeader(candidate.ID, candidate.Title))
}

recovery, recErr := recoverDanglingSuccess(
	w.Store, runtime.ProjectRoot, candidate.ID,
	assignee, now, emit,
)
if recErr != nil {
	if runtime.Log != nil {
		_, _ = fmt.Fprintf(runtime.Log, "dangling-success recovery error (%s): %v\n", candidate.ID, recErr)
	}
	_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
		return commitOutcomeError("recoverDanglingSuccess", assignee, result, recErr)
	})
	if ctx.Err() != nil {
		return result, ctx.Err()
	}
	continue
}
if recovery != nil {
	report := danglingSuccessRecoveryReport(candidate.ID, recovery)
	result.Attempts++
	if recovery.Outcome == danglingSuccessOutcomeClosed {
		result.Successes++
		result.LastSuccessAt = now().UTC()
	} else {
		result.Failures++
		result.LastFailureStatus = report.Status
	}
	result.Results = append(result.Results, report)
	if runtime.Log != nil {
		_, _ = fmt.Fprintln(runtime.Log, formatLoopResultLine(candidate.ID, report))
	}
	if finalizeDurableAuditOrStop(candidate.ID, report) {
		return result, nil
	}
	if applyStop(work.StopInput{Once: loopMode == executeloop.ModeOnce}) {
		return result, nil
	}
	continue
}

skipPreClaimIntake := false
readinessEstimatedDifficulty := ""

// Queue-level decomposition depth cap: when the bead has already been split
// to the configured limit, block it for operator review without invoking
// the classifier or splitter (docs/triage/decomposition.md §Recursion depth cap).
if runtime.PreClaimIntakeHook != nil && rcfg.MaxDecompositionDepth() > 0 {
	maxDepth := rcfg.MaxDecompositionDepth()
	depth := storeBeadDepth(ctx, w.Store, &candidate)
	if depth >= maxDepth {
		body, _ := json.Marshal(map[string]any{"depth": depth, "max": maxDepth})
		_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
			Kind:      "triage-overflow",
			Summary:   "depth cap exceeded",
			Body:      string(body),
			Actor:     assignee,
			Source:    "ddx work",
			CreatedAt: now().UTC(),
		})
		if lerr := addBeadLabel(ctx, w.Store, candidate.ID, "needs-human-decomposition"); lerr != nil && runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "triage-overflow label error: %v\n", lerr)
		}
		overflowDetail := fmt.Sprintf("bead depth %d reached max_decomposition_depth %d; operator must split", depth, maxDepth)
		if strictIntakeBlocking() {
			if parked, berr := parkBeadPostIntakeRejection(w.Store, &candidate, assignee, PreClaimIntakeOperatorRequired, "operator_required", overflowDetail, now().UTC()); berr != nil && runtime.Log != nil {
				_, _ = fmt.Fprintf(runtime.Log, "readiness park error: %v\n", berr)
			} else if parked {
				_ = releaseWorkerClaim(w.Store, candidate.ID, assignee)
				if stopAfterNonAttemptSkip() {
					applyStop(work.StopInput{Once: true})
					return result, nil
				}
				continue
			}
		} else {
			if appendPreClaimWarn(candidate.ID, "decomposition_depth_cap", overflowDetail, now().UTC()) {
				return result, nil
			}
			emit("pre_claim_intake.warn", readinessDecisionBody(
				"pre_claim_intake.decomposition_depth_cap",
				"too_large",
				"pre_claim_intake",
				"best-effort",
				"attempt",
				"continue with implementation; operator attention is reserved for explicit targeted execution",
				map[string]any{
					"bead_id": candidate.ID,
					"outcome": string(PreClaimIntakeTooLargeDecomposed),
					"detail":  overflowDetail,
				},
			))
			skipPreClaimIntake = true
		}
	}
}

// Pre-dispatch intake runs after claiming so that only the owning worker
// performs model-backed readiness evaluation. Concurrent workers that lose
// the claim race skip intake entirely (picker.claim_race above). Terminal
// non-actionable outcomes unclaim and park the bead so it does not
// re-appear in ReadyExecution until an operator reviews it.
if runtime.PreClaimIntakeHook != nil && !skipPreClaimIntake {
	if runtime.Log != nil {
		_, _ = fmt.Fprint(runtime.Log, workLog.FormatLifecycleLine(WorkLogLifecycleLine{
			Phase:    "readiness",
			BeadID:   candidate.ID,
			Message:  "check: starting",
			Harness:  harness,
			Provider: provider,
			Model:    model,
		}))
	}
	emit("pre_claim_intake.start", map[string]any{
		"bead_id": candidate.ID,
	})
	emitProgress(runtime.ProgressCh, ProgressEvent{
		EventID:   "evt-" + randomProgressID(),
		WorkerID:  runtime.WorkerID,
		ProjectID: runtime.ProjectRoot,
		BeadID:    candidate.ID,
		Phase:     "pre_claim_intake",
		Heartbeat: true,
		TS:        now().UTC(),
		Message:   "readiness check",
	})
	intakeResult, intakeErr := runPreClaimIntakeHookWithTimeout(ctx, runtime.PreClaimIntakeHook, candidate.ID, preClaimTimeout)
	if intakeErr == nil {
		readinessEstimatedDifficulty = normalizeReadinessEstimatedDifficulty(intakeResult.EstimatedDifficulty)
	}
	intakeOutcome := intakeResult.normalizedOutcome()
	if intakeResult.SystemReason == ReadinessSystemReasonTimeout {
		timeoutDetail := strings.TrimSpace(intakeResult.Detail)
		if timeoutDetail == "" {
			timeoutDetail = fmt.Sprintf("readiness check timed out after %s", preClaimTimeout)
		}
		if runtime.Log != nil {
			_, _ = fmt.Fprint(runtime.Log, workLog.FormatLifecycleLine(WorkLogLifecycleLine{
				Phase:    "readiness",
				BeadID:   candidate.ID,
				Message:  fmt.Sprintf("check timed out after %s (continuing)", preClaimTimeout),
				Harness:  harness,
				Provider: provider,
				Model:    model,
			}))
		}
		eventBody := readinessDecisionBody(
			"pre_claim_intake.timeout",
			"timeout",
			"pre_claim_intake",
			func() string {
				if strictIntakeBlocking() {
					return "block"
				}
				return "warn-only"
			}(),
			func() string {
				if strictIntakeBlocking() {
					return "park"
				}
				return "continue"
			}(),
			func() string {
				if strictIntakeBlocking() {
					return "review the readiness timeout and retry the bead later"
				}
				return "continue with implementation; review should create follow-up work for any readiness gaps"
			}(),
			map[string]any{
				"bead_id":       candidate.ID,
				"command":       "ddx work readiness check",
				"context":       "pre-claim intake",
				"detail":        timeoutDetail,
				"harness":       harness,
				"model":         model,
				"mode":          string(loopMode),
				"outcome":       string(PreClaimIntakeError),
				"provider":      provider,
				"system_reason": ReadinessSystemReasonTimeout,
				"targeted":      strictIntakeBlocking(),
				"timeout":       preClaimTimeout.String(),
				"worker_id":     runtime.WorkerID,
			},
		)
		operatorOverrideTimeout, _ := detectIntakeBlockedOperatorOverride(w.Store, &candidate, "pre_claim_intake.timeout", ReadinessReasonSystemUnready, "pre_claim_intake", "block", "park", "review intake result and accept, rewrite, split, block, or cancel")
		eventBody["operator_override"] = operatorOverrideTimeout
		if strictIntakeBlocking() {
			emit("pre_claim_intake.blocked", eventBody)
			if parked, berr := parkBeadPostIntakeRejection(w.Store, &candidate, assignee, PreClaimIntakeError, ReadinessReasonSystemUnready, timeoutDetail, now().UTC()); berr != nil && runtime.Log != nil {
				_, _ = fmt.Fprintf(runtime.Log, "readiness park error: %v\n", berr)
			} else if parked {
				if runtime.Log != nil {
					_, _ = fmt.Fprintf(runtime.Log, "readiness timeout parked bead %s for operator review\n", candidate.ID)
				}
			}
			_ = releaseWorkerClaim(w.Store, candidate.ID, assignee)
			if stopAfterNonAttemptSkip() {
				applyStop(work.StopInput{Once: true})
				return result, nil
			}
			continue
		} else {
			emit("pre_claim_intake.warn", eventBody)
			if appendPreClaimWarn(candidate.ID, "timeout", timeoutDetail, now().UTC()) {
				return result, nil
			}
			intakeOutcome = PreClaimIntakeActionableAtomic
		}
	}
	switch {
	case intakeErr != nil:
		if errors.Is(intakeErr, context.Canceled) || errors.Is(intakeErr, context.DeadlineExceeded) {
			if exitReason == "" {
				applyStop(work.StopInput{ContextErr: intakeErr})
			}
			return result, intakeErr
		}
		warning := trimDiagnosticPrefix(intakeErr.Error(), "pre-claim intake")
		classified := ClassifyReadiness(ReadinessClassificationSystemUnready, nil, warning)
		if runtime.Log != nil {
			_, _ = fmt.Fprint(runtime.Log, workLog.FormatLifecycleLine(WorkLogLifecycleLine{
				Phase:    "readiness",
				BeadID:   candidate.ID,
				Message:  fmt.Sprintf("check unavailable: %s (continuing)", warning),
				Harness:  harness,
				Provider: provider,
				Model:    model,
			}))
		}
		emit("pre_claim_intake.warn", readinessDecisionBody(
			"pre_claim_intake.system_unready",
			classified.Reason,
			"pre_claim_intake",
			"warn-only",
			"warn",
			"check the readiness route or harness configuration and retry",
			map[string]any{
				"bead_id":       candidate.ID,
				"outcome":       string(PreClaimIntakeError),
				"system_reason": classified.SystemReason,
				"detail":        warning,
			},
		))
		if appendPreClaimWarn(candidate.ID, "system_unready", warning, now().UTC()) {
			return result, nil
		}
	case intakeOutcome == PreClaimIntakeActionableAtomic:
		// pass-through
	case intakeOutcome == PreClaimIntakeActionableButRewritten:
		if err := applyPreClaimIntakeRewrite(w.Store, candidate.ID, assignee, intakeResult, now().UTC()); err != nil {
			warning := trimDiagnosticPrefix(err.Error(), "pre-claim intake rewrite")
			if runtime.Log != nil {
				_, _ = fmt.Fprintf(runtime.Log, "bead readiness: rewrite error: %s (continuing with original %s)\n", warning, candidate.ID)
			}
			emit("pre_claim_intake.warn", readinessDecisionBody(
				"pre_claim_intake.rewrite_rejected",
				"rewrite_rejected",
				"pre_claim_intake",
				"warn-only",
				"warn",
				"revise the rewrite so it preserves every explicit commitment",
				map[string]any{
					"bead_id": candidate.ID,
					"outcome": string(PreClaimIntakeActionableButRewritten),
					"detail":  warning,
				},
			))
			if appendPreClaimWarn(candidate.ID, "rewrite_rejected", warning, now().UTC()) {
				return result, nil
			}
		}
	case intakeOutcome == PreClaimIntakeError:
		warning := trimDiagnosticPrefix(intakeResult.Detail, "pre-claim intake")
		if warning == "" {
			warning = "readiness check returned intake_error"
		}
		reason := intakeResult.Reason
		systemReason := intakeResult.SystemReason
		if reason == "" && systemReason == "" {
			classified := ClassifyReadiness(ReadinessClassificationSystemUnready, nil, warning)
			reason = classified.Reason
			systemReason = classified.SystemReason
		}
		if runtime.Log != nil {
			_, _ = fmt.Fprint(runtime.Log, workLog.FormatLifecycleLine(WorkLogLifecycleLine{
				Phase:    "readiness",
				BeadID:   candidate.ID,
				Message:  fmt.Sprintf("check unavailable: %s (continuing)", warning),
				Harness:  harness,
				Provider: provider,
				Model:    model,
			}))
		}
		emit("pre_claim_intake.warn", readinessDecisionBody(
			"pre_claim_intake.system_unready",
			reason,
			"pre_claim_intake",
			"warn-only",
			"warn",
			"check the readiness route or harness configuration and retry",
			map[string]any{
				"bead_id":       candidate.ID,
				"outcome":       string(PreClaimIntakeError),
				"system_reason": systemReason,
				"detail":        warning,
			},
		))
		if appendPreClaimWarn(candidate.ID, "system_unready", warning, now().UTC()) {
			return result, nil
		}
	case intakeOutcome == PreClaimIntakeTooLargeDecomposed:
		// too_large_decomposed should move work forward by splitting before
		// claim. Some intake classifiers only identify the need to split;
		// when no concrete children are attached, ask the orchestrator
		// decomposer for executable child specs and then apply them.
		decomp := intakeResult.Decomposition
		if decomp == nil && runtime.PostAttemptDecompositionHook != nil {
			if runtime.Log != nil {
				_, _ = fmt.Fprintf(runtime.Log, "bead readiness requested decomposition; generating split (%s)\n", candidate.ID)
			}
			var hookErr error
			decomp, hookErr = runtime.PostAttemptDecompositionHook(ctx, candidate.ID)
			if hookErr != nil {
				if err := ctx.Err(); err != nil {
					applyStop(work.StopInput{ContextErr: err})
					return result, err
				}
				warning := fmt.Sprintf("decomposition hook unavailable: %s", hookErr.Error())
				if runtime.Log != nil {

		}
		*v = readinessVerdict(strings.ToLower(strings.TrimSpace(s)))
		return nil
	default:
		return fmt.Errorf("readiness_checks verdict must be a bool, string, or null, got %s", jsonKindName(trimmed[0]))
	}
}

func jsonKindName(first byte) string {
	switch first {
	case '{':
		return "object"
	case '[':
		return "array"
	case '"':
		return "string"
	case 't', 'f':
		return "bool"
	case 'n':
		return "null"
	default:
		return "number"
	}
}

type preClaimReadinessSuggestedFix struct {
	Target string `json:"target,omitempty"`
	Fix    string `json:"fix,omitempty"`
}

type preClaimReadinessDifficulty struct {
	EstimatedDifficulty string `json:"estimated_difficulty,omitempty"`
	Reason              string `json:"reason,omitempty"`
}

type preClaimReadinessScore struct {
	Present bool
}

func (s *preClaimReadinessScore) UnmarshalJSON(data []byte) error {
	trimmed := strings.TrimSpace(string(data))
	if trimmed == "" || trimmed == "null" {
		return nil
	}
	s.Present = true
	return nil
}

type preClaimReadinessSuggestedFixesPayload []preClaimReadinessSuggestedFix

func (p *preClaimReadinessSuggestedFixesPayload) UnmarshalJSON(data []byte) error {
	trimmed := strings.TrimSpace(string(data))
	if trimmed == "" || trimmed == "null" {
		return nil
	}
	if trimmed[0] != '[' {
		return fmt.Errorf("suggested_fixes must be a JSON array")
	}
	var raw []json.RawMessage
	if err := json.Unmarshal(data, &raw); err != nil {
		return err
	}
	fixes := make([]preClaimReadinessSuggestedFix, 0, len(raw))
	for _, item := range raw {
		itemTrimmed := strings.TrimSpace(string(item))
		if itemTrimmed == "" || itemTrimmed == "null" {
			continue
		}
		switch itemTrimmed[0] {
		case '"':
			var fix string
			if err := json.Unmarshal(item, &fix); err != nil {
				return err
			}
			fixes = append(fixes, preClaimReadinessSuggestedFix{Fix: strings.TrimSpace(fix)})
		case '{':
			var fix preClaimReadinessSuggestedFix
			if err := json.Unmarshal(item, &fix); err != nil {
				return err
			}
			fix.Target = strings.TrimSpace(fix.Target)
			fix.Fix = strings.TrimSpace(fix.Fix)
			fixes = append(fixes, fix)
		default:
			return fmt.Errorf("suggested_fixes entries must be strings or objects")
		}
	}
	*p = fixes
	return nil
}

func normalizeReadinessStringList(items []string) []string {
	if len(items) == 0 {
		return nil
	}
	out := make([]string, 0, len(items))
	for _, item := range items {
		item = strings.TrimSpace(item)
		if item == "" {
			continue
		}

		}
		out = append(out, item)
	}
	if len(out) == 0 {
		return nil
	}
	return out
}

func decodeReadinessStringListField(data []byte, fieldName string, splitLines bool) ([]string, error) {
	trimmed := strings.TrimSpace(string(data))
	if trimmed == "" || trimmed == "null" {
		return nil, nil
	}
	switch trimmed[0] {
	case '[':
		var items []string
		if err := json.Unmarshal(data, &items); err != nil {
			return nil, err
		}
		return normalizeReadinessStringList(items), nil
	case '"':
		var item string
		if err := json.Unmarshal(data, &item); err != nil {
			return nil, err
		}
		if splitLines {
			return normalizeReadinessStringList(strings.Split(item, "\n")), nil
		}
		return normalizeReadinessStringList([]string{item}), nil
	default:
		return nil, fmt.Errorf("%s must be a string or string array", fieldName)
	}
}

func decodeReadinessAcceptanceList(data []byte, fieldName string) ([]string, error) {
	return decodeReadinessStringListField(data, fieldName, true)
}

type preClaimReadinessSuggestedChild struct {
	Title       string   `json:"title,omitempty"`
	Description string   `json:"description,omitempty"`
	Acceptance  []string `json:"acceptance,omitempty"`
	Labels      []string `json:"labels,omitempty"`
	Parent      string   `json:"parent,omitempty"`
	Deps        []string `json:"deps,omitempty"`
}

func (c *preClaimReadinessSuggestedChild) UnmarshalJSON(data []byte) error {
	var raw struct {
		Title       string          `json:"title,omitempty"`
		Description string          `json:"description,omitempty"`
		Acceptance  json.RawMessage `json:"acceptance,omitempty"`
		Labels      []string        `json:"labels,omitempty"`
		Parent      string          `json:"parent,omitempty"`
		Deps        []string        `json:"deps,omitempty"`
	}
	if err := json.Unmarshal(data, &raw); err != nil {
		return err
	}
	acceptance, err := decodeReadinessAcceptanceList(raw.Acceptance, "suggested_child_beads[].acceptance")
	if err != nil {
		return err
	}
	c.Title = raw.Title
	c.Description = raw.Description
	c.Acceptance = acceptance
	c.Labels = raw.Labels
	c.Parent = raw.Parent
	c.Deps = raw.Deps
	return nil
}

type preClaimReadinessWaiver struct {
	Reason   string   `json:"reason,omitempty"`
	Criteria []string `json:"criteria,omitempty"`
	Evidence string   `json:"evidence,omitempty"`
}

func (w *preClaimReadinessWaiver) UnmarshalJSON(data []byte) error {
	var raw struct {
		Reason   string          `json:"reason,omitempty"`
		Criteria json.RawMessage `json:"criteria,omitempty"`
		Evidence string          `json:"evidence,omitempty"`
	}
	if err := json.Unmarshal(data, &raw); err != nil {
		return err
	}
	criteria, err := decodeReadinessStringListField(raw.Criteria, "waivers_applied[].criteria", false)
	if err != nil {
		return err
	}
	w.Reason = strings.TrimSpace(raw.Reason)
	w.Criteria = criteria
	w.Evidence = strings.TrimSpace(raw.Evidence)
	return nil
}

type preClaimReadinessWaiversPayload []preClaimReadinessWaiver

func (p *preClaimReadinessWaiversPayload) UnmarshalJSON(data []byte) error {
	trimmed := strings.TrimSpace(string(data))
	if trimmed == "" || trimmed == "null" {
		return nil
	}
	if trimmed[0] == '"' {
		var reason string
		if err := json.Unmarshal(data, &reason); err != nil {
			return err
		}
		reason = strings.TrimSpace(reason)
		if reason == "" {
			return nil
		}
		*p = []preClaimReadinessWaiver{{Reason: reason}}
		return nil
	}
	if trimmed[0] != '[' {
		return fmt.Errorf("waivers_applied must be a JSON array or string")
	}
	var raw []json.RawMessage

	for _, field := range fields {
		field = strings.ToLower(strings.TrimSpace(field))
		if field == "" {
			continue
		}
		if _, ok := seen[field]; ok {
			continue
		}
		seen[field] = struct{}{}
		out = append(out, field)
	}
	return out
}

func decodePreClaimIntakePayloadResultWithMode(payload string, qualityMode string) (PreClaimIntakeResult, error) {
	var probe struct {
		Classification  string                                 `json:"classification"`
		Outcome         string                                 `json:"outcome"`
		Tractability    string                                 `json:"tractability"`
		Rationale       string                                 `json:"rationale"`
		Score           preClaimReadinessScore                 `json:"score"`
		Difficulty      preClaimReadinessDifficulty            `json:"difficulty"`
		ReadinessChecks preClaimReadinessChecksPayload         `json:"readiness_checks"`
		SuggestedFixes  preClaimReadinessSuggestedFixesPayload `json:"suggested_fixes"`
	}
	if err := json.Unmarshal([]byte(payload), &probe); err != nil {
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode result: %w", err)
	}
	if probe.Outcome != "" {
		return decodeCanonicalReadinessPayloadWithMode(payload, qualityMode)
	}
	if probe.Classification != "" {
		if isReadinessClassificationPayload(probe.Classification, probe.Tractability, probe.Rationale, probe.Score.Present, normalizeReadinessEstimatedDifficulty(probe.Difficulty.EstimatedDifficulty) != "", probe.ReadinessChecks.Present, probe.ReadinessChecks.Len(), len(probe.SuggestedFixes)) {
			return decodeReadinessClassificationPayloadWithMode(payload, qualityMode)
		}
		return decodeLegacyIntakePayload(payload)
	}
	return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing classification or outcome field")
}

func isReadinessClassificationPayload(classification, tractability, rationale string, scorePresent, difficultyPresent bool, readinessChecksPresent bool, checkCount, fixCount int) bool {
	switch strings.ToLower(strings.TrimSpace(classification)) {
	case ReadinessClassificationSystemUnready,
		"readiness_error",
		"intake_error",
		ReadinessClassificationNeedsRefine,
		ReadinessClassificationNeedsSplit,
		ReadinessClassificationOperatorRequired,
		"ambiguous",
		"safely_refinable",
		"split":
		return true
	case "ready":
		return readinessChecksPresent ||
			strings.TrimSpace(tractability) != "" ||
			strings.TrimSpace(rationale) != "" ||
			scorePresent ||
			difficultyPresent ||
			checkCount > 0 ||
			fixCount > 0
	default:
		return false
	}
}

func decodeCanonicalReadinessPayloadWithMode(payload string, qualityMode string) (PreClaimIntakeResult, error) {
	var out preClaimReadinessPromptResult
	if err := json.Unmarshal([]byte(payload), &out); err != nil {
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode readiness result: %w", err)
	}
	detail := strings.TrimSpace(out.Reason)
	if detail == "" {
		detail = strings.TrimSpace(out.Detail)
	}
	rewrite := PreClaimIntakeRewrite{
		Description:   strings.TrimSpace(out.Rewrite.Description),
		Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
		ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
	}
	estimatedDifficulty := normalizeReadinessEstimatedDifficulty(out.Difficulty.EstimatedDifficulty)
	switch strings.ToLower(strings.TrimSpace(out.Outcome)) {
	case "actionable_atomic":
		return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: detail, EstimatedDifficulty: estimatedDifficulty}, nil
	case "actionable_but_rewritten":
		return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableButRewritten, Detail: detail, EstimatedDifficulty: estimatedDifficulty, Rewrite: rewrite}, nil
	case "too_large_decomposed":
		return PreClaimIntakeResult{Outcome: PreClaimIntakeTooLargeDecomposed, Reason: ReadinessReasonTooLarge, Detail: detail, EstimatedDifficulty: estimatedDifficulty}, nil
	case "operator_required", "human_review_required":
		return PreClaimIntakeResult{Outcome: PreClaimIntakeOperatorRequired, Reason: ReadinessReasonAmbiguousScope, Detail: detail, EstimatedDifficulty: estimatedDifficulty}, nil
	case "ambiguous_needs_human", "needs_human":
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: legacy readiness outcome %q removed by lifecycle migration; use %q", out.Outcome, PreClaimIntakeOperatorRequired)
	case "readiness_error", "system_unready":
		// system_unready maps to fail-open/skip per ADR-023/FEAT-010 policy
		classified := ClassifyReadinessWithMode(ReadinessClassificationSystemUnready, nil, detail, qualityMode)
		return PreClaimIntakeResult{
			Outcome:      PreClaimIntakeError,
			Reason:       classified.Reason,
			SystemReason: classified.SystemReason,
			Detail:       detail,
		}, nil
	case "":
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing outcome")
	default:
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: unknown readiness outcome %q: expected one of actionable_atomic, actionable_but_rewritten, too_large_decomposed, operator_required, readiness_error, system_unready", out.Outcome)
	}
}

func decodeReadinessClassificationPayloadWithMode(payload string, qualityMode string) (PreClaimIntakeResult, error) {
	var out preClaimReadinessClassificationPromptResult
	if err := json.Unmarshal([]byte(payload), &out); err != nil {
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode readiness classification result: %w", err)
	}
	if out.ReadinessChecks.Malformed != "" {
		detail := malformedReadinessChecksDetail(out.ReadinessChecks)
		classified := ClassifyReadinessWithMode(ReadinessClassificationSystemUnready, nil, detail, qualityMode)
		return PreClaimIntakeResult{
			Outcome:      classified.IntakeOutcome,
			Reason:       classified.Reason,
			SystemReason: classified.SystemReason,
			Detail:       detail,
		}, nil
	}
	reasons := failedReadinessReasons(out.ReadinessChecks.Checks)
	detail := firstNonEmptyReadinessDetail(out.Rationale, out.Detail, out.Reasoning)
	classified := ClassifyReadinessWithMode(out.Classification, reasons, detail, qualityMode)
	if detail == "" {
		detail = readinessCheckEvidence(out.ReadinessChecks.Checks)
	}
	detail = readinessDetailWithReason(classified, detail)

	rewrite := PreClaimIntakeRewrite{
		Description:   strings.TrimSpace(out.Rewrite.Description),
		Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
		ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
	}
	result := PreClaimIntakeResult{
		Outcome:             classified.IntakeOutcome,
		Reason:              classified.Reason,
		SystemReason:        classified.SystemReason,
		Detail:              detail,
		EstimatedDifficulty: normalizeReadinessEstimatedDifficulty(out.Difficulty.EstimatedDifficulty),
	}
	if classified.Classification == ReadinessClassificationNeedsRefine && hasPreClaimIntakeRewrite(rewrite) {
		result.Outcome = PreClaimIntakeActionableButRewritten
		result.Rewrite = rewrite
	}
	return result, nil
}

func failedReadinessReasons(checks []preClaimReadinessCheck) []string {
	reasons := make([]string, 0, len(checks))
	for _, check := range checks {
		verdict := strings.ToLower(strings.TrimSpace(string(check.Verdict)))
		if verdict != "fail" {
			continue
		}
		if reason := strings.TrimSpace(check.Reason); reason != "" {
			reasons = append(reasons, reason)
		}
	}
	return reasons

	return reasons
}

func malformedReadinessChecksDetail(checks preClaimReadinessChecksPayload) string {
	detail := strings.TrimSpace(checks.Malformed)
	if detail == "" {
		detail = "readiness_checks must be an object or array"
	}
	if evidence := strings.TrimSpace(checks.Evidence); evidence != "" {
		detail += ": " + strconv.Quote(evidence)
	}
	return detail
}

func readinessCheckEvidence(checks []preClaimReadinessCheck) string {
	for _, check := range checks {
		if strings.ToLower(strings.TrimSpace(string(check.Verdict))) != "fail" {
			continue
		}
		if evidence := strings.TrimSpace(check.Evidence); evidence != "" {
			return evidence
		}
	}
	return ""
}

func readinessDetailWithReason(classified ReadinessClassificationResult, detail string) string {
	detail = strings.TrimSpace(detail)
	reason := strings.TrimSpace(classified.Reason)
	if reason == "" {
		return detail
	}
	if detail == "" {
		return reason
	}
	if strings.Contains(strings.ToLower(detail), strings.ToLower(reason)) {
		return detail
	}
	return reason + ": " + detail
}

func firstNonEmptyReadinessDetail(values ...string) string {
	for _, value := range values {
		if trimmed := strings.TrimSpace(value); trimmed != "" {
			return trimmed
		}
	}
	return ""
}

func hasPreClaimIntakeRewrite(rewrite PreClaimIntakeRewrite) bool {
	return strings.TrimSpace(rewrite.Description) != "" ||
		strings.TrimSpace(rewrite.Acceptance) != "" ||
		len(rewrite.ChangedFields) > 0
}

func normalizeReadinessEstimatedDifficulty(raw string) string {
	switch strings.ToLower(strings.TrimSpace(raw)) {
	case string(escalation.DifficultyEasy):
		return string(escalation.DifficultyEasy)
	case string(escalation.DifficultyMedium):
		return string(escalation.DifficultyMedium)
	case string(escalation.DifficultyHard):
		return string(escalation.DifficultyHard)
	default:
		return ""
	}
}

func decodeLegacyIntakePayload(payload string) (PreClaimIntakeResult, error) {
	var out preClaimIntakePromptResult
	if err := json.Unmarshal([]byte(payload), &out); err != nil {
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode result: %w", err)
	}
	switch strings.ToLower(strings.TrimSpace(out.Classification)) {
	case "atomic", "ok", "ready", "actionable", "pass":
		return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: strings.TrimSpace(out.Reasoning)}, nil
	case "rewritten":
		return PreClaimIntakeResult{
			Outcome: PreClaimIntakeActionableButRewritten,
			Detail:  strings.TrimSpace(out.Reasoning),
			Rewrite: PreClaimIntakeRewrite{
				Description:   strings.TrimSpace(out.Rewrite.Description),
				Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
				ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
			},
		}, nil
	case "decomposable":
		return PreClaimIntakeResult{Outcome: PreClaimIntakeTooLargeDecomposed, Detail: strings.TrimSpace(out.Reasoning)}, nil
	case "ambiguous", "ambiguous_scope", "needs_human", "ambiguous_needs_human":
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: legacy classification %q removed by lifecycle migration; use outcome %q", out.Classification, PreClaimIntakeOperatorRequired)
	case "":
		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing classification")
	default:
		return PreClaimIntakeResult{}, fmt.Errorf(
			"pre-claim intake: unknown classification %q: expected one of ready, needs_refine, needs_split, operator_required, system_unready",
			out.Classification,
		)
	}
}

