// attemptTermination records which guard (the progress watchdog or the
// external-close watcher) terminated an attempt. Both guards run concurrently;
// set serialises them so only the first to fire releases the lease, and reason
// is read after the guards have stopped so the loop knows to skip normal
// failure escalation for an already-handled termination.
type attemptTermination struct {
	mu     sync.Mutex
	reason string
}

// set records reason and reports whether this caller was the first to fire. A
// second guard firing observes reason already set and returns false so it does
// not double-release the lease.
func (t *attemptTermination) set(reason string) bool {
	t.mu.Lock()
	defer t.mu.Unlock()

func applyPreClaimDecomposition(ctx context.Context, store ExecuteBeadLoopStore, parent *bead.Bead, decomp *PreClaimDecomposition, actor string, at time.Time) ([]string, error) {
	childIDs := make([]string, 0, len(decomp.Children))
	for _, child := range decomp.Children {
		nb := &bead.Bead{
			Title:       child.Title,
			Description: child.Description,
			Acceptance:  child.Acceptance,
			Labels:      append([]string(nil), child.Labels...),
			Parent:      parent.ID,
		}
		if err := store.Create(ctx, nb); err != nil {
			return childIDs, fmt.Errorf("decompose: create child %q: %w", child.Title, err)
		}
		childIDs = append(childIDs, nb.ID)
	}

	// Park the parent so it does not re-enter execution while the generated
	// children are outstanding.
	if err := store.Update(ctx, parent.ID, func(b *bead.Bead) {
		ensureBeadExtra(b)
		b.Extra[bead.ExtraExecutionElig] = false
	}); err != nil {
		return childIDs, fmt.Errorf("decompose: park parent %s after decomposition: %w", parent.ID, err)
	}

	body, _ := json.Marshal(map[string]any{
		"child_ids": childIDs,
		"rationale": decomp.Rationale,
		"ac_map":    decomp.ACMap,
	})
	return childIDs, store.AppendEvent(parent.ID, bead.BeadEvent{
		Kind:      "triage-decomposed",
		Summary:   fmt.Sprintf("decomposed into %s", strings.Join(childIDs, ", ")),
		Body:      string(body),
		Actor:     actor,
		Source:    "ddx work",
		CreatedAt: at,
	})
}

// parkBeadPostIntakeRejection moves the bead to proposed and appends an
// intake.blocked event so the bead is filtered from ReadyExecution until an
// operator reviews the intake decision. It does not release the worker-owned
// claim — the caller must release it after this returns (whether or not
// parking succeeds).
func parkBeadPostIntakeRejection(store ExecuteBeadLoopStore, candidate *bead.Bead, actor string, outcome PreClaimIntakeOutcome, reason, detail string, at time.Time) (bool, error) {
	if candidate == nil {
		return false, fmt.Errorf("pre-claim intake park requires a bead candidate")
	}
	reason = strings.TrimSpace(reason)
	if reason == "" {
		reason = string(outcome)
	}
	detail = strings.TrimSpace(detail)
	if detail == "" {
		detail = reason
	}
	ruleID := "pre_claim_intake." + strings.TrimSpace(string(outcome))
	findingFingerprint := preClaimIntakeFindingFingerprint(candidate, ruleID, reason, "pre_claim_intake", "block", "park", "review intake result and accept, rewrite, split, block, or cancel")
	promptFingerprint := bead.PromptFingerprint(*candidate)
	if honored, err := preClaimIntakeOverrideHonored(store, candidate, findingFingerprint); err != nil {
		return false, err
	} else if honored {
		appendPreClaimIntakeOverrideHonoredEvent(store, candidate.ID, actor, findingFingerprint, promptFingerprint, at)
		return false, nil
	}
	body := readinessDecisionBody(
		ruleID,
		reason,
		"pre_claim_intake",
		"block",
		"park",
		"review intake result and accept, rewrite, split, block, or cancel",
		map[string]any{
			"intake_outcome":       string(outcome),
			"detail":               detail,
			"operator_override":    false,
			"prompt_fingerprint":   promptFingerprint,

		ID:         "ddx-root-mutation-parent",
		Title:      "parent bead",
		Acceptance: "1. parent criterion",
	}
	require.NoError(t, store.Create(context.Background(), parent))
	childStore := &backEdgeDecompositionStore{Store: store, parentID: parent.ID}
	child := &bead.Bead{
		ID:         "ddx-root-mutation-child",
		Parent:     parent.ID,
		Title:      "child bead",
		Acceptance: "1. child criterion",
	}
	require.NoError(t, childStore.Create(context.Background(), child))

	var eventSink bytes.Buffer
	var logBuf bytes.Buffer
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-root-mutation",
				ResultRev: "abc123",
			}, nil
		}),
	}

	hook := NewPreClaimIntakeHook(root, store, intakeHookTestConfig(), nil, preClaimIntakeHookRunnerFunc(func(opts RunArgs) (*Result, error) {
		require.NoError(t, os.WriteFile(filepath.Join(root, "lifecycle-sentinel.txt"), []byte("sentinel\n"), 0o644))
		return &Result{
			ExitCode: 0,
			Output:   `{"classification":"atomic","confidence":0.99,"reasoning":"ready"}`,
		}, nil
	}))

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:               true,
		TargetBeadID:       child.ID,
		EventSink:          &eventSink,
		Log:                &logBuf,
		PreClaimIntakeHook: hook,
	})
	require.NoError(t, err)
	require.NotNil(t, result)

	assert.Contains(t, eventSink.String(), "pre_claim_intake.error")
	assert.Contains(t, eventSink.String(), child.ID)
	assert.Contains(t, eventSink.String(), "project root mutation rejected")
	assert.Contains(t, logBuf.String(), "check error")
	assert.Contains(t, logBuf.String(), child.ID)
}

func TestIntake_HookRunsAfterClaim(t *testing.T) {
	inner, _, _ := newExecuteLoopTestStore(t)
	var preflightSeen int32
	var intakeSeen int32
	store := &claimCountingStore{
		Store: inner,
		beforeClaim: func() {
			if atomic.LoadInt32(&preflightSeen) == 0 {
				t.Fatal("route preflight must run before Claim")
			}
			// Claim now happens BEFORE intake: intake must NOT have run yet.
			if atomic.LoadInt32(&intakeSeen) != 0 {
				t.Fatal("Claim must run before PreClaimIntakeHook")
			}
		},
	}

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				SessionID: "sess-intake-order",
				ResultRev: "fedcba",
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker", Harness: "claude", Model: "claude-sonnet-4-6"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once: true,
		RoutePreflight: func(ctx context.Context, harness, model string) error {
			atomic.StoreInt32(&preflightSeen, 1)
			return nil
		},
		PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
			if atomic.LoadInt32(&preflightSeen) == 0 {
				t.Fatal("PreClaimIntakeHook must run after route preflight")
			}
			if atomic.LoadInt32(&store.claimCalls) == 0 {
				t.Fatal("PreClaimIntakeHook must run after Claim")
			}
			atomic.StoreInt32(&intakeSeen, 1)
			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic}, nil
		},
	})
	require.NoError(t, err)
	require.NotNil(t, result)

	assert.Equal(t, int32(1), atomic.LoadInt32(&preflightSeen), "route preflight must run")
	assert.Equal(t, int32(1), atomic.LoadInt32(&intakeSeen), "intake hook must run")
	assert.Equal(t, int32(1), atomic.LoadInt32(&store.claimCalls), "Claim must run before intake")
}

